import React, { useState, useEffect } from 'react';
import { getLiveStats } from '../services/api';

function LiveStats() {
  const [stats, setStats] = useState({
    cpu_usage: 0,
    memory_usage: 0,
    memory_used_gb: 0,
    memory_total_gb: 0,
    gpu_usage: null,
    power_consumption: 0,
    co2_emissions: 0
  });
  const [showInfo, setShowInfo] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const response = await getLiveStats();
        console.log('✅ Live stats received:', response.data);

        // Ensure all values are numbers, not undefined
        const safeStats = {
          cpu_usage: response.data?.cpu_usage ?? 0,
          memory_usage: response.data?.memory_usage ?? 0,
          memory_used_gb: response.data?.memory_used_gb ?? 0,
          memory_total_gb: response.data?.memory_total_gb ?? 0,
          gpu_usage: response.data?.gpu_usage ?? null,
          power_consumption: response.data?.power_consumption ?? 0,
          co2_emissions: response.data?.co2_emissions ?? 0
        };

        setStats(safeStats);
        setIsLoading(false);
        setError(null);
      } catch (error) {
        console.error('❌ Error fetching live stats:', error);
        setError(error.message);
        setIsLoading(false);
      }
    };

    fetchStats();
    const interval = setInterval(fetchStats, 1000);
    return () => clearInterval(interval);
  }, []);

  const formatNumber = (value, decimals = 2) => {
    if (value === null || value === undefined || isNaN(value)) return '0.00';
    const num = Number(value);
    return num.toFixed(decimals);
  };

  const InfoIcon = ({ type }) => (
    <span
      className="info-icon"
      onMouseEnter={() => setShowInfo(type)}
      onMouseLeave={() => setShowInfo(null)}
      style={{
        cursor: 'help',
        marginLeft: '8px',
        fontSize: '0.75rem',
        color: 'var(--accent-blue)',
        border: '1px solid var(--accent-blue)',
        borderRadius: '50%',
        padding: '2px 6px',
        display: 'inline-block',
        width: '18px',
        height: '18px',
        textAlign: 'center',
        lineHeight: '14px',
        transition: 'all 0.3s ease'
      }}
    >
      i
    </span>
  );

  const Tooltip = ({ text }) => (
    <div style={{
      position: 'absolute',
      backgroundColor: 'rgba(0, 0, 0, 0.9)',
      color: '#fff',
      padding: '12px',
      borderRadius: 'var(--radius-sm)',
      fontSize: '0.85rem',
      zIndex: 100,
      maxWidth: '240px',
      marginTop: '8px',
      boxShadow: 'var(--shadow-lg)',
      left: '20px',
      border: '1px solid rgba(255, 255, 255, 0.1)',
      animation: 'fadeIn 0.2s ease-out'
    }}>
      {text}
    </div>
  );

  const StatCard = ({ icon, label, value, unit, color, infoType, infoText, delay, subValue }) => (
    <div
      className="glass-card fade-in"
      style={{
        position: 'relative',
        padding: 'var(--spacing-lg)',
        borderLeft: `4px solid ${color}`,
        animationDelay: `${delay}ms`
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: '12px' }}>
        <span style={{ fontSize: '1.5rem', marginRight: '12px' }}>{icon}</span>
        <p style={{ margin: 0, color: 'var(--text-secondary)', fontSize: '0.9rem', fontWeight: 500 }}>
          {label}
          {infoType && <InfoIcon type={infoType} />}
        </p>
      </div>
      <p style={{
        margin: 0,
        fontSize: '2rem',
        fontWeight: 700,
        background: `linear-gradient(135deg, ${color}, ${color}dd)`,
        WebkitBackgroundClip: 'text',
        WebkitTextFillColor: 'transparent',
        backgroundClip: 'text',
        lineHeight: 1.2
      }}>
        {value}
        {unit && <span style={{ fontSize: '1rem', opacity: 0.8, marginLeft: '4px' }}>{unit}</span>}
      </p>
      {subValue && (
        <p style={{
          margin: '8px 0 0 0',
          fontSize: '0.85rem',
          color: 'var(--text-muted)',
          fontWeight: 500
        }}>
          {subValue}
        </p>
      )}
      {showInfo === infoType && <Tooltip text={infoText} />}
    </div>
  );

  const infoText = {
    co2: "CO₂ emissions calculated based on real-time power consumption and regional carbon intensity (mg/s).",
    power: "Estimated power usage based on CPU/GPU TDP and current workload activity.",
    memory: "Live memory utilization showing absolute usage against total system capacity."
  };

  if (error) {
    return (
      <div style={{ marginBottom: 'var(--spacing-2xl)' }}>
        <div className="glass-card" style={{ padding: 'var(--spacing-xl)', textAlign: 'center' }}>
          <span style={{ fontSize: '3rem' }}>⚠️</span>
          <h3 style={{ color: 'var(--text-primary)', marginTop: '16px' }}>Backend Connection Error</h3>
          <p style={{ color: 'var(--text-secondary)' }}>
            Cannot connect to backend at http://localhost:8000
          </p>
          <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem', marginTop: '8px' }}>
            Please start the backend: <code style={{ background: 'rgba(255,255,255,0.1)', padding: '4px 8px', borderRadius: '4px' }}>uvicorn app.main:app --reload</code>
          </p>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div style={{ marginBottom: 'var(--spacing-2xl)' }}>
        <div style={{
          display: 'flex',
          alignItems: 'center',
          marginBottom: 'var(--spacing-xl)'
        }}>
          <div style={{
            width: '4px',
            height: '32px',
            background: 'var(--primary-gradient)',
            borderRadius: '2px',
            marginRight: '16px'
          }}></div>
          <h2 style={{
            fontSize: '1.75rem',
            fontWeight: 700,
            margin: 0,
            color: 'var(--text-primary)'
          }}>
            Real-Time System Monitoring
          </h2>
        </div>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: 'var(--spacing-lg)'
        }}>
          {[1, 2, 3, 4, 5].map(i => (
            <div key={i} className="shimmer glass-card" style={{ height: '120px' }}></div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div style={{ marginBottom: 'var(--spacing-2xl)' }}>
      <div style={{
        display: 'flex',
        alignItems: 'center',
        marginBottom: 'var(--spacing-xl)',
        animation: 'fadeIn 0.6s ease-out'
      }}>
        <div style={{
          width: '4px',
          height: '32px',
          background: 'var(--primary-gradient)',
          borderRadius: '2px',
          marginRight: '16px'
        }}></div>
        <h2 style={{
          fontSize: '1.75rem',
          fontWeight: 700,
          margin: 0,
          color: 'var(--text-primary)'
        }}>
          Real-Time System Monitoring
        </h2>
      </div>

      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: 'var(--spacing-lg)'
      }}>
        <StatCard
          icon="💻"
          label="CPU Usage"
          value={formatNumber(stats.cpu_usage, 1)}
          unit="%"
          color="var(--accent-blue)"
          delay={0}
        />

        <StatCard
          icon="🧠"
          label="Memory Usage"
          value={`${formatNumber(stats.memory_used_gb, 2)} / ${formatNumber(stats.memory_total_gb, 2)}`}
          unit="GB"
          color="var(--accent-purple)"
          infoType="memory"
          infoText={infoText.memory}
          delay={100}
          subValue={`${formatNumber(stats.memory_usage, 1)}% utilized`}
        />

        {stats.gpu_usage !== null && (
          <StatCard
            icon="🎮"
            label="GPU Usage"
            value={formatNumber(stats.gpu_usage, 1)}
            unit="%"
            color="var(--accent-pink)"
            delay={200}
          />
        )}

        <StatCard
          icon="⚡"
          label="Power Consumption"
          value={formatNumber(stats.power_consumption, 2)}
          unit="W"
          color="var(--accent-orange)"
          infoType="power"
          infoText={infoText.power}
          delay={stats.gpu_usage !== null ? 300 : 200}
        />

        <StatCard
          icon="🌱"
          label="CO₂ Emissions"
          value={formatNumber(stats.co2_emissions, 4)}
          unit="mg/s"
          color="var(--accent-green)"
          infoType="co2"
          infoText={infoText.co2}
          delay={stats.gpu_usage !== null ? 400 : 300}
        />
      </div>
    </div>
  );
}

export default LiveStats;
